import{_ as e,c as d,a0 as r,o as i}from"./chunks/framework.B6JXc2q-.js";const _=JSON.parse('{"title":"认证运行时恢复路径规范","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_runtime_reload_recovery_path.md","filePath":"spec/auth_runtime_reload_recovery_path.md"}'),a={name:"spec/auth_runtime_reload_recovery_path.md"};function o(l,t,n,s,u,c){return i(),d("div",null,t[0]||(t[0]=[r('<h1 id="认证运行时恢复路径规范" tabindex="-1">认证运行时恢复路径规范 <a class="header-anchor" href="#认证运行时恢复路径规范" aria-label="Permalink to &quot;认证运行时恢复路径规范&quot;">​</a></h1><p>版本：v1.0 状态：1.0.9 专项约束文档 最后更新：2026-03-29 适用范围：<code>xiaomusic/auth.py</code> 内 runtime reload / runtime rebind / verify 路径的行为边界</p><hr><h2 id="_1-文档目的" tabindex="-1">1. 文档目的 <a class="header-anchor" href="#_1-文档目的" aria-label="Permalink to &quot;1. 文档目的&quot;">​</a></h2><p>当前自动恢复失败的主要矛盾已从 short session rebuild 进一步转移到 runtime reload 闭环。</p><ul><li>primary / fallback 路径负责获取 token</li><li>short session rebuild 负责&quot;盘上没有 short session&quot;的场景</li><li>runtime reload 负责&quot;盘上已有 short session，但运行时未恢复&quot;的场景</li></ul><p>当前新暴露的主问题：</p><ul><li>UI 显示&quot;登录待恢复&quot;而非&quot;未登录&quot;</li><li>这类状态现在会自动尝试一次 runtime reload，而不是只等用户点击按钮</li><li><code>persistent_auth_available=true</code>、<code>short_session_available=true</code></li><li>但 <code>runtime_seed_has_serviceToken=false</code>、<code>mina_service_rebuilt=false</code>、<code>verify_result=failed</code></li></ul><p>本文档解决：</p><ul><li>runtime reload 的定位、入口条件、执行边界、结果分类、可观测性要求</li></ul><p>本文档不解决：</p><ul><li>为什么 Xiaomi 云端返回 401</li><li>short session rebuild 的规范（已有 <code>auth_recovery_fallback_path.md</code>）</li><li>QR 登录流程本身</li><li>整套 auth.py 模块拆分</li></ul><hr><h2 id="_2-术语与范围" tabindex="-1">2. 术语与范围 <a class="header-anchor" href="#_2-术语与范围" aria-label="Permalink to &quot;2. 术语与范围&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>定义</th></tr></thead><tbody><tr><td>runtime reload</td><td>从磁盘已存在的 auth 数据重建运行时状态的完整流程</td></tr><tr><td>runtime seed</td><td>运行时初始化所需的认证种子数据（serviceToken、ssecurity 等）</td></tr><tr><td>runtime rebind</td><td>重新初始化 mina_service / miio_service 实例</td></tr><tr><td>verify</td><td>调用 device_list 验证运行时可用性</td></tr><tr><td>runtime reload trigger</td><td>runtime reload 的触发方式（手动或自动）</td></tr><tr><td>manual refresh runtime</td><td>用户手动触发的运行时刷新（<code>POST /api/auth/refresh_runtime</code>）</td></tr><tr><td>auto runtime reload</td><td>受控自动触发的 runtime reload</td></tr><tr><td>登录待恢复 / login pending recovery</td><td>long-lived auth 和 short session 均在，但运行时未 ready 的状态</td></tr><tr><td>short session available</td><td>盘上存在 serviceToken 或 yetAnotherServiceToken</td></tr><tr><td>persistent auth available</td><td>盘上存在长期态字段（passToken、psecurity、ssecurity 等）</td></tr><tr><td>degraded</td><td>认证状态异常，部分能力可能不可用</td></tr><tr><td>locked</td><td>认证锁定，需要人工干预（扫码登录）</td></tr></tbody></table><p><strong>本文档中的 runtime reload 专指</strong>：<code>manual_reload_runtime</code> 及其调用链；触发可以来自手动按钮，也可以来自受控自动调度。</p><p><strong>不包括</strong>：</p><ul><li>short session rebuild（<code>_rebuild_short_session_from_persistent_auth</code>）</li><li>primary path（<code>miaccount_persistent_auth_login</code>）</li><li>fallback path（<code>mijia_persistent_auth_login</code>）</li><li>manual QR login 本身</li></ul><hr><h2 id="_3-当前已知链路事实" tabindex="-1">3. 当前已知链路事实 <a class="header-anchor" href="#_3-当前已知链路事实" aria-label="Permalink to &quot;3. 当前已知链路事实&quot;">​</a></h2><p>以下为本文档的现实前提，不是推测：</p><ol><li><p>short session 已在盘上</p><ul><li><code>disk_has_serviceToken=true</code></li><li><code>disk_has_yetAnotherServiceToken=true</code></li></ul></li><li><p>但 runtime seed 不完整</p><ul><li><code>runtime_seed_has_serviceToken=false</code></li></ul></li><li><p>service 实例未重建成功</p><ul><li><code>mina_service_rebuilt=false</code></li></ul></li><li><p>verify 失败</p><ul><li><code>verify_result=failed</code></li></ul></li><li><p>系统状态表现为</p><ul><li><code>auth_mode=degraded</code></li><li>UI 显示&quot;登录待恢复&quot;</li><li>后端会在满足条件时自动调度一次 runtime reload</li></ul></li><li><p>当前问题不是 token writeback，而是运行时恢复闭环未完成</p></li></ol><hr><h2 id="_4-runtime-reload-path-的定位" tabindex="-1">4. runtime reload path 的定位 <a class="header-anchor" href="#_4-runtime-reload-path-的定位" aria-label="Permalink to &quot;4. runtime reload path 的定位&quot;">​</a></h2><ul><li>runtime reload 不是 short session rebuild</li><li>runtime reload 不是 primary / fallback</li><li>runtime reload 的职责是： <ul><li>从盘上已存在的 auth 数据重建 runtime</li><li>建立 runtime seed</li><li>重建 mina_service / miio_service</li><li>执行 verify</li></ul></li><li>runtime reload 不是 manual login 本身</li><li>runtime reload 是&quot;登录后待恢复态&quot;的恢复闭环核心路径</li></ul><hr><h2 id="_5-runtime-reload-的入口条件" tabindex="-1">5. runtime reload 的入口条件 <a class="header-anchor" href="#_5-runtime-reload-的入口条件" aria-label="Permalink to &quot;5. runtime reload 的入口条件&quot;">​</a></h2><h3 id="_5-1-允许进入的条件" tabindex="-1">5.1 允许进入的条件 <a class="header-anchor" href="#_5-1-允许进入的条件" aria-label="Permalink to &quot;5.1 允许进入的条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><code>persistent_auth_available=true</code></td><td>长期态仍在</td></tr><tr><td><code>short_session_available=true</code></td><td>short session 已在盘上</td></tr><tr><td>auth 数据已在盘上</td><td>token_store 可加载</td></tr><tr><td>当前运行时未 ready</td><td><code>runtime_auth_ready=false</code></td></tr><tr><td><code>auth_mode=degraded</code></td><td>处于登录待恢复语义</td></tr><tr><td>当前没有进行中的同类恢复</td><td>受 singleflight / recovery gate 保护</td></tr><tr><td>不在 cooldown/backoff 中</td><td>避免恢复风暴</td></tr></tbody></table><p>当前触发上下文：</p><ul><li><code>manual_refresh_runtime</code>（用户手动点击&quot;刷新运行时&quot;）</li><li><code>init_all_data()</code> / <code>keepalive_loop()</code> 的受控自动触发</li></ul><h3 id="_5-2-禁止进入的条件" tabindex="-1">5.2 禁止进入的条件 <a class="header-anchor" href="#_5-2-禁止进入的条件" aria-label="Permalink to &quot;5.2 禁止进入的条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>缺少 short session</td><td>应走 short session rebuild 路径</td></tr><tr><td>缺少长期态字段</td><td>应走 primary / fallback 路径或进入 locked</td></tr><tr><td>已进入 locked</td><td>需要人工干预</td></tr><tr><td>当前运行时已经 ready</td><td>无需重复 reload</td></tr><tr><td>short session rebuild 尚未完成</td><td>不应误入 runtime reload</td></tr></tbody></table><hr><h2 id="_6-runtime-reload-的执行边界" tabindex="-1">6. runtime reload 的执行边界 <a class="header-anchor" href="#_6-runtime-reload-的执行边界" aria-label="Permalink to &quot;6. runtime reload 的执行边界&quot;">​</a></h2><h3 id="_6-1-可以做的事" tabindex="-1">6.1 可以做的事 <a class="header-anchor" href="#_6-1-可以做的事" aria-label="Permalink to &quot;6.1 可以做的事&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为</th><th>说明</th></tr></thead><tbody><tr><td>从磁盘重新加载 auth 数据</td><td><code>token_store.reload_from_disk()</code></td></tr><tr><td>检查 disk token presence</td><td><code>disk_has_serviceToken</code> / <code>disk_has_yetAnotherServiceToken</code></td></tr><tr><td>建立 runtime seed</td><td>基于盘上 token 初始化运行时认证种子</td></tr><tr><td>重建 mina_service / miio_service</td><td><code>rebuild_services()</code></td></tr><tr><td>执行 verify</td><td>调用 device_list 验证</td></tr><tr><td>在成功时进入 healthy</td><td><code>auth_mode=healthy</code></td></tr><tr><td>在失败时保留 degraded</td><td>并暴露明确原因</td></tr></tbody></table><h3 id="_6-2-不能做的事" tabindex="-1">6.2 不能做的事 <a class="header-anchor" href="#_6-2-不能做的事" aria-label="Permalink to &quot;6.2 不能做的事&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行为</th><th>说明</th></tr></thead><tbody><tr><td>不得隐式重建 short session</td><td>runtime reload 不负责 token 获取</td></tr><tr><td>不得把 short session 缺失伪装成 runtime rebind 失败</td><td>应用 <code>short_session_missing_for_runtime_reload</code></td></tr><tr><td>不得在 runtime seed 不完整时伪装成 runtime ready</td><td>应暴露 <code>runtime_seed_incomplete</code></td></tr><tr><td>不得隐式切换成 manual login</td><td>runtime reload 失败不等于立即 manual login</td></tr><tr><td>不得绕过统一认证状态语义</td><td>必须通过 <code>rebuild_services</code></td></tr><tr><td>不得因为 runtime reload 失败就清掉长期态</td><td>失败应停在 degraded</td></tr></tbody></table><h3 id="_6-3-明确的阶段边界" tabindex="-1">6.3 明确的阶段边界 <a class="header-anchor" href="#_6-3-明确的阶段边界" aria-label="Permalink to &quot;6.3 明确的阶段边界&quot;">​</a></h3><p>runtime reload 必须拆分为以下阶段，不得混写为一个模糊失败：</p><table tabindex="0"><thead><tr><th>阶段</th><th>说明</th></tr></thead><tbody><tr><td>磁盘态检查</td><td><code>token_store_reloaded</code>、<code>disk_has_serviceToken</code></td></tr><tr><td>runtime seed 建立</td><td>基于盘上 token 初始化认证种子</td></tr><tr><td>service 实例重建</td><td><code>mina_service_rebuilt</code>、<code>miio_service_rebuilt</code></td></tr><tr><td>verify</td><td>调用 device_list 验证运行时可用性</td></tr><tr><td>device map refresh</td><td>更新设备信息</td></tr></tbody></table><hr><h2 id="_7-登录待恢复-状态定义" tabindex="-1">7. &quot;登录待恢复&quot;状态定义 <a class="header-anchor" href="#_7-登录待恢复-状态定义" aria-label="Permalink to &quot;7. &quot;登录待恢复&quot;状态定义&quot;">​</a></h2><h3 id="_7-1-状态语义" tabindex="-1">7.1 状态语义 <a class="header-anchor" href="#_7-1-状态语义" aria-label="Permalink to &quot;7.1 状态语义&quot;">​</a></h3><p>&quot;登录待恢复&quot;不是&quot;未登录&quot;。</p><p>它表示：</p><ul><li>至少长期态已在</li><li>可能 short session 已在盘上</li><li>但运行时尚未 ready</li><li>当前实现会在满足条件时自动尝试一次 runtime reload</li></ul><h3 id="_7-2-对应后端状态" tabindex="-1">7.2 对应后端状态 <a class="header-anchor" href="#_7-2-对应后端状态" aria-label="Permalink to &quot;7.2 对应后端状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>典型值</th></tr></thead><tbody><tr><td><code>auth_mode</code></td><td><code>degraded</code></td></tr><tr><td><code>persistent_auth_available</code></td><td><code>true</code></td></tr><tr><td><code>short_session_available</code></td><td><code>true</code></td></tr><tr><td><code>runtime_rebind_result</code></td><td><code>failed</code> 或未执行</td></tr><tr><td><code>verify_result</code></td><td><code>failed</code> 或未执行</td></tr><tr><td><code>auto_runtime_reload_triggered</code></td><td><code>true</code> 或未触发</td></tr></tbody></table><h3 id="_7-3-ui-显示约束" tabindex="-1">7.3 UI 显示约束 <a class="header-anchor" href="#_7-3-ui-显示约束" aria-label="Permalink to &quot;7.3 UI 显示约束&quot;">​</a></h3><ul><li>UI 显示&quot;刷新运行时&quot;时，后端应处于上述状态</li><li>这些状态现在也可能由自动调度进入，不再必须等待人工点击</li><li>以下状态不应显示为&quot;登录待恢复&quot;： <ul><li><code>locked</code>（应显示&quot;需要重新登录&quot;）</li><li><code>persistent_auth_available=false</code>（应显示&quot;需要重新登录&quot;）</li><li><code>short_session_available=false</code>（应显示&quot;登录中&quot;或类似）</li></ul></li></ul><hr><h2 id="_8-runtime-reload-的结果分类" tabindex="-1">8. runtime reload 的结果分类 <a class="header-anchor" href="#_8-runtime-reload-的结果分类" aria-label="Permalink to &quot;8. runtime reload 的结果分类&quot;">​</a></h2><h3 id="_8-1-结果分类表" tabindex="-1">8.1 结果分类表 <a class="header-anchor" href="#_8-1-结果分类表" aria-label="Permalink to &quot;8.1 结果分类表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>error_code</th><th>含义</th><th>发生阶段</th><th>允许重试</th><th>应保持 degraded</th><th>应建议 manual login</th></tr></thead><tbody><tr><td><code>&quot;&quot;</code> (ok)</td><td>成功恢复运行时</td><td>-</td><td>-</td><td>否</td><td>否</td></tr><tr><td><code>missing_long_lived_auth_fields</code></td><td>长期态字段缺失</td><td>磁盘检查</td><td>否</td><td>是</td><td>是</td></tr><tr><td><code>short_session_missing_for_runtime_reload</code></td><td>short session 缺失</td><td>磁盘检查</td><td>否</td><td>是</td><td>视情况</td></tr><tr><td><code>runtime_seed_incomplete</code></td><td>runtime seed 不完整</td><td>seed 建立</td><td>短期可重试</td><td>是</td><td>否</td></tr><tr><td><code>runtime_rebind_failed</code></td><td>service 实例重建失败</td><td>rebind</td><td>短期可重试</td><td>是</td><td>否</td></tr><tr><td><code>runtime_verify_failed</code></td><td>device_list 验证失败</td><td>verify</td><td>短期可重试</td><td>是</td><td>视情况</td></tr><tr><td><code>RuntimeError</code> 等</td><td>未知异常</td><td>任意阶段</td><td>短期可重试</td><td>是</td><td>否</td></tr></tbody></table><h3 id="_8-2-特别区分" tabindex="-1">8.2 特别区分 <a class="header-anchor" href="#_8-2-特别区分" aria-label="Permalink to &quot;8.2 特别区分&quot;">​</a></h3><ul><li><strong>token 缺失导致不能开始</strong>：<code>missing_long_lived_auth_fields</code>、<code>short_session_missing_for_runtime_reload</code></li><li><strong>token 存在但 seed 不完整</strong>：<code>runtime_seed_incomplete</code></li><li><strong>service 重建失败</strong>：<code>runtime_rebind_failed</code></li><li><strong>verify 失败</strong>：<code>runtime_verify_failed</code></li></ul><h3 id="_8-3-失败类型约束" tabindex="-1">8.3 失败类型约束 <a class="header-anchor" href="#_8-3-失败类型约束" aria-label="Permalink to &quot;8.3 失败类型约束&quot;">​</a></h3><ul><li><code>verify_auth_failure_detected=true</code>：表示现有 short session 已被 MiNA 证伪，runtime reload 应 handoff 到既有 short-session 恢复链</li><li>网络/连接错误：例如 timeout、<code>Cannot connect to host</code>、DNS 失败等，不应被当作 auth failure，应该保留 degraded 并进入 cooldown/backoff</li><li>其它 runtime 失败：保留阶段化错误码，不要混成 <code>runtime_verify_failed</code></li></ul><hr><h2 id="_9-runtime-reload-与其他路径的边界关系" tabindex="-1">9. runtime reload 与其他路径的边界关系 <a class="header-anchor" href="#_9-runtime-reload-与其他路径的边界关系" aria-label="Permalink to &quot;9. runtime reload 与其他路径的边界关系&quot;">​</a></h2><h3 id="_9-1-与-short-session-rebuild-的边界" tabindex="-1">9.1 与 short session rebuild 的边界 <a class="header-anchor" href="#_9-1-与-short-session-rebuild-的边界" aria-label="Permalink to &quot;9.1 与 short session rebuild 的边界&quot;">​</a></h3><ul><li>short session rebuild 解决&quot;盘上没有 short session&quot;</li><li>runtime reload 解决&quot;盘上有 short session，但 runtime 未恢复&quot;</li><li>两者不是同一路径</li><li>不能混用错误码</li></ul><h3 id="_9-2-与-primary-fallback-的边界" tabindex="-1">9.2 与 primary / fallback 的边界 <a class="header-anchor" href="#_9-2-与-primary-fallback-的边界" aria-label="Permalink to &quot;9.2 与 primary / fallback 的边界&quot;">​</a></h3><ul><li>primary / fallback 负责拿 token</li><li>runtime reload 负责消费盘上已有 token 重建运行时</li><li>primary/fallback 失败不应伪装成 runtime reload 失败</li><li>runtime reload 失败不应反向覆盖 primary/fallback 分类</li></ul><h3 id="_9-3-与-manual-login-的边界" tabindex="-1">9.3 与 manual login 的边界 <a class="header-anchor" href="#_9-3-与-manual-login-的边界" aria-label="Permalink to &quot;9.3 与 manual login 的边界&quot;">​</a></h3><ul><li>manual login 可更新认证态</li><li>但 manual login 成功不等于 runtime ready</li><li>runtime reload 是 manual login 后闭环的重要后续阶段</li><li>manual login 本身不属于 runtime reload</li></ul><h3 id="_9-4-与-degraded-locked-的边界" tabindex="-1">9.4 与 degraded / locked 的边界 <a class="header-anchor" href="#_9-4-与-degraded-locked-的边界" aria-label="Permalink to &quot;9.4 与 degraded / locked 的边界&quot;">​</a></h3><ul><li>runtime reload 失败通常应停在 degraded</li><li>只有长期态缺失或人工干预必要时才讨论 locked</li><li>不能因为一次 verify 失败就直接进入 locked</li></ul><h3 id="_9-5-与自动-runtime-reload-的边界" tabindex="-1">9.5 与自动 runtime reload 的边界 <a class="header-anchor" href="#_9-5-与自动-runtime-reload-的边界" aria-label="Permalink to &quot;9.5 与自动 runtime reload 的边界&quot;">​</a></h3><ul><li>自动 runtime reload 只是触发方式，不改变 runtime reload 的阶段语义</li><li>自动触发必须满足 <code>degraded + persistent_auth_available + short_session_available + 无同类恢复 + 无 backoff</code></li><li>自动触发失败后应进入 cooldown/backoff，避免恢复风暴</li><li>自动触发和手动 <code>refresh_runtime</code> 共享同一 runtime reload 核心链路</li></ul><hr><h2 id="_10-可观测性要求" tabindex="-1">10. 可观测性要求 <a class="header-anchor" href="#_10-可观测性要求" aria-label="Permalink to &quot;10. 可观测性要求&quot;">​</a></h2><h3 id="_10-1-必须稳定暴露的字段" tabindex="-1">10.1 必须稳定暴露的字段 <a class="header-anchor" href="#_10-1-必须稳定暴露的字段" aria-label="Permalink to &quot;10.1 必须稳定暴露的字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>token_store_reloaded</code></td><td>是否成功重新加载 token_store</td></tr><tr><td><code>disk_has_serviceToken</code></td><td>盘上是否存在 serviceToken</td></tr><tr><td><code>disk_has_yetAnotherServiceToken</code></td><td>盘上是否存在 yetAnotherServiceToken</td></tr><tr><td><code>runtime_seed_has_serviceToken</code></td><td>runtime seed 中是否有 serviceToken</td></tr><tr><td><code>mina_service_rebuilt</code></td><td>mina_service 是否重建成功</td></tr><tr><td><code>miio_service_rebuilt</code></td><td>miio_service 是否重建成功</td></tr><tr><td><code>device_map_refreshed</code></td><td>device map 是否刷新成功</td></tr><tr><td><code>verify_result</code></td><td>verify 结果（<code>ok</code> / <code>failed</code>）</td></tr><tr><td><code>error_code</code></td><td>错误分类码</td></tr><tr><td><code>error_message</code></td><td>错误描述</td></tr><tr><td><code>auto_runtime_reload_triggered</code></td><td>是否由自动调度触发</td></tr><tr><td><code>auto_runtime_reload_source</code></td><td>触发来源（<code>init_all_data</code> / <code>keepalive</code>）</td></tr><tr><td><code>auto_runtime_reload_result</code></td><td>自动触发结果</td></tr><tr><td><code>auto_runtime_reload_skipped_reason</code></td><td>未触发或跳过原因</td></tr><tr><td><code>auto_runtime_reload_backoff_until</code></td><td>自动触发冷却截止时间</td></tr><tr><td><code>recovery_chain_handoff</code></td><td>verify auth failure 后是否 handoff 到短期态恢复链</td></tr><tr><td><code>short_session_invalidated_after_verify</code></td><td>verify 证伪后是否清理 short session</td></tr></tbody></table><h3 id="_10-2-关键约束" tabindex="-1">10.2 关键约束 <a class="header-anchor" href="#_10-2-关键约束" aria-label="Permalink to &quot;10.2 关键约束&quot;">​</a></h3><ul><li>不能让&quot;登录待恢复&quot;再次回到黑盒状态</li><li>必须能区分是 token 缺、seed 缺、service 没建起来、还是 verify 失败</li><li><code>runtime_seed_has_serviceToken</code> 是判断 seed 是否完整的关键指标</li></ul><hr><h2 id="_11-最小侵入修补约束" tabindex="-1">11. 最小侵入修补约束 <a class="header-anchor" href="#_11-最小侵入修补约束" aria-label="Permalink to &quot;11. 最小侵入修补约束&quot;">​</a></h2><p>后续修补应遵守：</p><table tabindex="0"><thead><tr><th>约束</th><th>说明</th></tr></thead><tbody><tr><td>优先增强 runtime reload 闭环的稳定性与可观测性</td><td>细化错误分类</td></tr><tr><td>不应大改 auth state machine</td><td>保持 <code>degraded</code> / <code>locked</code> 语义不变</td></tr><tr><td>不应重写 singleflight</td><td>singleflight 约束由 <code>auth_recovery_singleflight.md</code> 定义</td></tr><tr><td>不应把 runtime reload 和 short session rebuild 混在一起</td><td>两者是不同路径</td></tr><tr><td>不应因为修 runtime reload 而破坏 primary/fallback 已收口的行为</td><td>已收口的错误分类应保留</td></tr><tr><td>不应先改 UI，再倒推后端</td><td>应先明确后端状态定义</td></tr></tbody></table><p>可写的后续方向类型（仅作为约束，不是实现）：</p><ul><li>明确 runtime seed 不完整的稳定错误码</li><li>明确&quot;登录待恢复&quot;的后端判定</li><li>明确扫码登录成功后是否应该自动触发 runtime reload</li><li>明确 verify 失败后的终态</li></ul><p>但不要写成具体代码方案。</p><hr><h2 id="_12-非目标" tabindex="-1">12. 非目标 <a class="header-anchor" href="#_12-非目标" aria-label="Permalink to &quot;12. 非目标&quot;">​</a></h2><p>本文档不解决：</p><ul><li>不解决 Xiaomi 云端为什么返回 401</li><li>不解决 miservice 依赖内部实现</li><li>不解决二维码 UI 交互设计</li><li>不解决整个 auth.py 模块拆分</li><li>不解决大规模重构方案</li></ul>',89)]))}const m=e(a,[["render",o]]);export{_ as __pageData,m as default};
